import { type ClassValue, clsx } from "clsx";
import { twMerge } from "tailwind-merge";

export function cn(...inputs: ClassValue[]) {
  return twMerge(clsx(inputs));
}

export function formatPrice(amount: number): string {
  return `${amount.toLocaleString("ar-EG")} ج.م`;
}

export const DELIVERY_FEE = 15;
export const TAX_RATE = 0.14;

export function calculateCartTotals(subtotal: number) {
  const deliveryFee = subtotal > 0 ? DELIVERY_FEE : 0;
  const tax = Math.round(subtotal * TAX_RATE);
  const total = subtotal + deliveryFee + tax;
  return { deliveryFee, tax, total };
}

import { gsap } from "gsap";
import { ScrollTrigger } from "gsap/ScrollTrigger";

let registered = false;

export function registerGsapPlugins() {
  if (typeof window === "undefined" || registered) return;
  gsap.registerPlugin(ScrollTrigger);
  registered = true;
}

export const fadeUpReveal = {
  hidden: { opacity: 0, y: 60, filter: "blur(12px)" },
  visible: {
    opacity: 1,
    y: 0,
    filter: "blur(0px)",
    transition: { duration: 0.9, ease: [0.22, 1, 0.36, 1] },
  },
};

export const staggerContainer = {
  hidden: { opacity: 0 },
  visible: {
    opacity: 1,
    transition: { staggerChildren: 0.12, delayChildren: 0.1 },
  },
};

export function animateSectionReveal(
  selector: string,
  options?: { start?: string; y?: number }
) {
  registerGsapPlugins();
  const elements = document.querySelectorAll(selector);
  if (!elements.length) return;

  gsap.fromTo(
    elements,
    {
      opacity: 0,
      y: options?.y ?? 80,
      filter: "blur(16px)",
      scale: 0.96,
    },
    {
      opacity: 1,
      y: 0,
      filter: "blur(0px)",
      scale: 1,
      duration: 1.1,
      ease: "power3.out",
      stagger: 0.1,
      scrollTrigger: {
        trigger: elements[0]?.parentElement ?? elements[0],
        start: options?.start ?? "top 80%",
        toggleActions: "play none none reverse",
      },
    }
  );
}

export function animateParallax(
  element: HTMLElement | null,
  speed = 0.3
) {
  if (!element) return () => {};
  registerGsapPlugins();

  const tween = gsap.to(element, {
    yPercent: speed * 100,
    ease: "none",
    scrollTrigger: {
      trigger: element,
      start: "top bottom",
      end: "bottom top",
      scrub: true,
    },
  });

  return () => tween.kill();
}

"use client";

import { useEffect } from "react";
import Lenis from "lenis";
import { gsap } from "gsap";
import { ScrollTrigger } from "gsap/ScrollTrigger";

export function useLenis() {
  useEffect(() => {
    const lenis = new Lenis({
      duration: 1.4,
      easing: (t) => Math.min(1, 1.001 - Math.pow(2, -10 * t)),
      smoothWheel: true,
      touchMultiplier: 1.8,
    });

    gsap.registerPlugin(ScrollTrigger);

    lenis.on("scroll", ScrollTrigger.update);

    const raf = (time: number) => {
      lenis.raf(time);
      requestAnimationFrame(raf);
    };
    requestAnimationFrame(raf);

    return () => {
      lenis.destroy();
    };
  }, []);
}

"use client";

import { useCallback, useRef } from "react";

export function useMagnetic(strength = 0.35) {
  const ref = useRef<HTMLButtonElement | HTMLAnchorElement>(null);

  const onMouseMove = useCallback(
    (e: React.MouseEvent) => {
      const el = ref.current;
      if (!el) return;
      const rect = el.getBoundingClientRect();
      const x = e.clientX - rect.left - rect.width / 2;
      const y = e.clientY - rect.top - rect.height / 2;
      el.style.transform = `translate(${x * strength}px, ${y * strength}px)`;
    },
    [strength]
  );

  const onMouseLeave = useCallback(() => {
    const el = ref.current;
    if (!el) return;
    el.style.transform = "translate(0px, 0px)";
  }, []);

  return { ref, onMouseMove, onMouseLeave };
}

"use client";

import {
  createContext,
  useCallback,
  useContext,
  useMemo,
  useState,
  type ReactNode,
} from "react";
import type { CartItem, MenuItem } from "@/types";
import { calculateCartTotals } from "@/lib/utils";

interface FlyAnimation {
  id: string;
  image: string;
  from: DOMRect;
}

interface CartContextValue {
  items: CartItem[];
  isOpen: boolean;
  subtotal: number;
  deliveryFee: number;
  tax: number;
  total: number;
  itemCount: number;
  flyAnimation: FlyAnimation | null;
  openCart: () => void;
  closeCart: () => void;
  toggleCart: () => void;
  addItem: (item: MenuItem, sourceRect?: DOMRect) => void;
  removeItem: (id: string) => void;
  updateQuantity: (id: string, quantity: number) => void;
  clearFlyAnimation: () => void;
}

const CartContext = createContext<CartContextValue | null>(null);

export function CartProvider({ children }: { children: ReactNode }) {
  const [items, setItems] = useState<CartItem[]>([]);
  const [isOpen, setIsOpen] = useState(false);
  const [flyAnimation, setFlyAnimation] = useState<FlyAnimation | null>(null);

  const subtotal = useMemo(
    () => items.reduce((sum, item) => sum + item.price * item.quantity, 0),
    [items]
  );

  const { deliveryFee, tax, total } = useMemo(
    () => calculateCartTotals(subtotal),
    [subtotal]
  );

  const itemCount = useMemo(
    () => items.reduce((sum, item) => sum + item.quantity, 0),
    [items]
  );

  const addItem = useCallback((item: MenuItem, sourceRect?: DOMRect) => {
    setItems((prev) => {
      const existing = prev.find((i) => i.id === item.id);
      if (existing) {
        return prev.map((i) =>
          i.id === item.id ? { ...i, quantity: i.quantity + 1 } : i
        );
      }
      return [...prev, { ...item, quantity: 1 }];
    });

    if (sourceRect) {
      setFlyAnimation({
        id: `${item.id}-${Date.now()}`,
        image: item.image,
        from: sourceRect,
      });
      setTimeout(() => setFlyAnimation(null), 900);
    }
  }, []);

  const removeItem = useCallback((id: string) => {
    setItems((prev) => prev.filter((i) => i.id !== id));
  }, []);

  const updateQuantity = useCallback((id: string, quantity: number) => {
    if (quantity <= 0) {
      setItems((prev) => prev.filter((i) => i.id !== id));
      return;
    }
    setItems((prev) =>
      prev.map((i) => (i.id === id ? { ...i, quantity } : i))
    );
  }, []);

  const value: CartContextValue = {
    items,
    isOpen,
    subtotal,
    deliveryFee,
    tax,
    total,
    itemCount,
    flyAnimation,
    openCart: () => setIsOpen(true),
    closeCart: () => setIsOpen(false),
    toggleCart: () => setIsOpen((o) => !o),
    addItem,
    removeItem,
    updateQuantity,
    clearFlyAnimation: () => setFlyAnimation(null),
  };

  return <CartContext.Provider value={value}>{children}</CartContext.Provider>;
}

export function useCart() {
  const ctx = useContext(CartContext);
  if (!ctx) throw new Error("useCart must be used within CartProvider");
  return ctx;
}

@tailwind base;
@tailwind components;
@tailwind utilities;

:root {
  --void: #050505;
  --pizza: #ff8c1a;
  --neon: #39ff14;
  --cream: #f5f5f0;
}

* {
  box-sizing: border-box;
}

html {
  scroll-behavior: auto;
}

html.lenis,
html.lenis body {
  height: auto;
}

.lenis.lenis-smooth {
  scroll-behavior: auto !important;
}

body {
  background: var(--void);
  color: var(--cream);
  overflow-x: hidden;
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
}

::selection {
  background: rgba(255, 140, 26, 0.35);
  color: #fff;
}

/* Film grain overlay */
.grain-overlay {
  pointer-events: none;
  position: fixed;
  inset: 0;
  z-index: 9998;
  opacity: 0.04;
  background-image: url("data:image/svg+xml,%3Csvg viewBox='0 0 256 256' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='noise'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.9' numOctaves='4' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23noise)'/%3E%3C/svg%3E");
  animation: grainShift 0.5s steps(2) infinite;
}

@keyframes grainShift {
  0%,
  100% {
    transform: translate(0, 0);
  }
  50% {
    transform: translate(-2%, -2%);
  }
}

/* Vignette */
.vignette {
  pointer-events: none;
  background: radial-gradient(
    ellipse at center,
    transparent 40%,
    rgba(5, 5, 5, 0.85) 100%
  );
}

/* Glass panel */
.glass-panel {
  background: linear-gradient(
    135deg,
    rgba(255, 255, 255, 0.08) 0%,
    rgba(255, 255, 255, 0.02) 100%
  );
  backdrop-filter: blur(24px) saturate(180%);
  -webkit-backdrop-filter: blur(24px) saturate(180%);
  border: 1px solid rgba(255, 255, 255, 0.1);
}

/* Light leak accent */
.light-leak::before {
  content: "";
  position: absolute;
  inset: -50%;
  background: conic-gradient(
    from 200deg at 30% 20%,
    rgba(255, 140, 26, 0.12),
    transparent 35%,
    rgba(57, 255, 20, 0.06),
    transparent 65%
  );
  pointer-events: none;
  animation: leakRotate 20s linear infinite;
}

@keyframes leakRotate {
  to {
    transform: rotate(360deg);
  }
}

/* Hero video slow zoom */
.hero-video-zoom {
  animation: heroZoom 22s ease-in-out infinite alternate;
}

@keyframes heroZoom {
  from {
    transform: scale(1);
  }
  to {
    transform: scale(1.12);
  }
}

/* Scroll indicator */
.scroll-line {
  animation: scrollPulse 2s ease-in-out infinite;
}

@keyframes scrollPulse {
  0%,
  100% {
    transform: scaleY(0.3);
    opacity: 0.4;
  }
  50% {
    transform: scaleY(1);
    opacity: 1;
  }
}

/* Shimmer button */
.btn-shimmer {
  background-size: 200% 100%;
  background-image: linear-gradient(
    90deg,
    #ff8c1a 0%,
    #ffb347 25%,
    #ff8c1a 50%,
    #ffb347 75%,
    #ff8c1a 100%
  );
  animation: shimmer 3s linear infinite;
}

/* Custom scrollbar */
::-webkit-scrollbar {
  width: 6px;
}

::-webkit-scrollbar-track {
  background: #050505;
}

::-webkit-scrollbar-thumb {
  background: rgba(255, 140, 26, 0.4);
  border-radius: 3px;
}

/* Section spacing */
.section-pad {
  @apply px-5 py-24 md:px-10 md:py-32 lg:px-16;
}

"use client";

import { motion } from "framer-motion";
import { useMemo } from "react";

interface Particle {
  id: number;
  x: number;
  y: number;
  size: number;
  duration: number;
  delay: number;
}

export function FloatingParticles({ count = 24 }: { count?: number }) {
  const particles = useMemo<Particle[]>(() => {
    return Array.from({ length: count }, (_, i) => ({
      id: i,
      x: Math.random() * 100,
      y: Math.random() * 100,
      size: Math.random() * 3 + 1,
      duration: Math.random() * 8 + 6,
      delay: Math.random() * 4,
    }));
  }, [count]);

  return (
    <motion.div
      className="pointer-events-none absolute inset-0 overflow-hidden"
      aria-hidden
    >
      {particles.map((p) => (
        <motion.span
          key={p.id}
          className="absolute rounded-full bg-pizza/30"
          style={{
            left: `${p.x}%`,
            top: `${p.y}%`,
            width: p.size,
            height: p.size,
          }}
          animate={{
            y: [0, -30, 0],
            opacity: [0.2, 0.8, 0.2],
            scale: [1, 1.5, 1],
          }}
          transition={{
            duration: p.duration,
            delay: p.delay,
            repeat: Infinity,
            ease: "easeInOut",
          }}
        />
      ))}
    </motion.div>
  );
}

"use client";

import { motion } from "framer-motion";
import { useMagnetic } from "@/hooks/useMagnetic";
import { cn } from "@/lib/utils";
import type { ReactNode, ButtonHTMLAttributes } from "react";

interface MagneticButtonProps extends ButtonHTMLAttributes<HTMLButtonElement> {
  children: ReactNode;
  variant?: "primary" | "ghost" | "outline";
  className?: string;
}

export function MagneticButton({
  children,
  variant = "primary",
  className,
  ...props
}: MagneticButtonProps) {
  const { ref, onMouseMove, onMouseLeave } = useMagnetic(0.25);

  const variants = {
    primary:
      "btn-shimmer text-void font-bold shadow-glow hover:shadow-[0_0_60px_rgba(255,140,26,0.5)]",
    ghost: "text-cream/80 hover:text-cream bg-transparent",
    outline:
      "border border-cream/20 text-cream hover:border-pizza/50 hover:text-pizza",
  };

  return (
    <motion.button
      ref={ref as React.RefObject<HTMLButtonElement>}
      onMouseMove={onMouseMove}
      onMouseLeave={onMouseLeave}
      whileTap={{ scale: 0.96 }}
      transition={{ type: "spring", stiffness: 400, damping: 25 }}
      className={cn(
        "relative inline-flex items-center justify-center gap-2 rounded-full px-8 py-4 text-sm md:text-base transition-shadow duration-500",
        variants[variant],
        className
      )}
      {...props}
    >
      {children}
    </motion.button>
  );
}

